// src/components/home.jsx
import React, { useEffect, useState, useRef } from "react";
import "../styles/home.css";
import { Link, useNavigate } from "react-router-dom";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function Home({ rooms: initialRooms = [] }) {
  const [index, setIndex] = useState(1);
  const slideCount = 3;
  const autoPlayRef = useRef(null);
  const navigate = useNavigate();

  // 🔐 AUTH STATE
  const [user, setUser] = useState(localStorage.getItem("username"));

  const [rooms, setRooms] = useState([]);
  const [loadingRooms, setLoadingRooms] = useState(false);
  const [roomsError, setRoomsError] = useState("");

  const [gallery, setGallery] = useState([]);
  const [loadingGallery, setLoadingGallery] = useState(false);

  /* ------------------ SLIDER ------------------ */
  useEffect(() => {
    autoPlayRef.current = setInterval(() => {
      setIndex((i) => (i >= slideCount ? 1 : i + 1));
    }, 6000);
    return () => clearInterval(autoPlayRef.current);
  }, []);

  /* ------------------ ANIMATIONS ------------------ */
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("show");
          }
        });
      },
      { threshold: 0.1 }
    );

    document
      .querySelectorAll(".fade-in, .fade-up, .fade-left, .fade-right")
      .forEach((el) => {
        if (!el.closest(".hero-wrap") && !el.closest(".nav")) {
          observer.observe(el);
        }
      });

    return () => observer.disconnect();
  }, []);

  /* ------------------ DATA ------------------ */
  useEffect(() => {
    if (Array.isArray(initialRooms) && initialRooms.length > 0) {
      setRooms(initialRooms.map(normalizeRoom));
      return;
    }
    fetchRooms();
    fetchGallery();
    // eslint-disable-next-line
  }, []);

  async function fetchRooms() {
    setLoadingRooms(true);
    setRoomsError("");
    try {
      const res = await axios.get(`${API_BASE}/api/rooms/`);
      const data = Array.isArray(res.data) ? res.data : [];
      setRooms(data.map(normalizeRoom));
    } catch {
      setRoomsError("Unable to load rooms.");
    } finally {
      setLoadingRooms(false);
    }
  }

  async function fetchGallery() {
    setLoadingGallery(true);
    try {
      const res = await axios.get(`${API_BASE}/api/gallery/`);
      setGallery(res.data);
    } catch {}
    finally {
      setLoadingGallery(false);
    }
  }

  /* ------------------ LOGOUT ------------------ */
  function logout() {
    localStorage.clear();
    setUser(null);
    navigate("/");
  }

  /* ------------------ ROOM NORMALIZER ------------------ */
  function normalizeRoom(r) {
    const id = r.id ?? r.room_id;
    const preview =
      r.images?.[0]?.url ||
      r.image ||
      r.image_path ||
      "/assets/images/uploads/default.jpg";

    return {
      id,
      room_id: id,
      room_name: r.room_name,
      capacity: r.capacity,
      price: r.price,
      image: preview.startsWith("http") ? preview : `${API_BASE}${preview}`,
    };
  }

  const slideBackground = (n) => ({
    backgroundImage: `url('/assets/images/glamp${n}.jpg')`,
  });

  return (
    <div id="app">
      <div className="slider">
        {/* SLIDES */}
        {[1, 2, 3].map((n) => (
          <div
            key={n}
            className={`slide ${index === n ? "active" : ""}`}
            style={slideBackground(n)}
          />
        ))}

        {/* NAVBAR */}
        <header className="nav">
          <div className="nav-inner">
            <div className="brand">
              <img src="/assets/images/glamp_logo.png" alt="Logo" className="logo" />
            </div>

            <nav className="menu">
              <Link to="/">Home</Link>
              <a href="#rooms">Rooms</a>
              <Link to="/reservation">Reservation</Link>

              {/* 🔐 AUTH BUTTONS */}
              {user ? (
                <>
                  <span className="user">Hi, {user}</span>
                  <button className="reserve" onClick={logout}>
                    Logout
                  </button>
                </>
              ) : (
                <Link className="reserve" to="/login">
                  Login
                </Link>
              )}
            </nav>
          </div>
        </header>

        {/* HERO */}
        <div className="hero-wrap">
          <h1>Experience Hospitality Like Never Before</h1>
          <p>Luxury, comfort & nature combined</p>
        </div>
      </div>

      {/* ROOMS */}
      <section id="rooms" className="accommodation">
        {loadingRooms ? (
          <p>Loading rooms...</p>
        ) : (
          <div className="rooms-grid">
            {rooms.map((room) => (
              <div key={room.id} className="room-card">
                <img src={room.image} alt={room.room_name} />
                <h3>{room.room_name}</h3>
                <p>{room.capacity} Guests</p>
                <span>From ₹{room.price}</span>
                <Link to={`/room/${room.id}`} className="details-btn">
                  View Details
                </Link>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* INSTAGRAM */}
      <section className="instagram">
        <div className="insta-gallery">
          {gallery.map((g) => (
            <img key={g.id} src={g.image_url} alt="Gallery" />
          ))}
        </div>
      </section>

      {/* FOOTER */}
      <footer className="footer">
        <p>© The Paradise Glamp</p>
      </footer>
    </div>
  );
}
